before_code:
module fsm_counter(
  input clk, rst_n,
  input [15:0] limit,
  output reg [15:0] count
);
  always @(posedge clk)
  begin
    if (count == limit)
      count <= 16'h0000;
    else
      count <= count + 1'b1;
  end
endmodule

after_code:
module fsm_counter(
  input clk, rst_n,
  input [15:0] limit,
  output reg [15:0] count
);
  always @(posedge clk or negedge rst_n)
  begin
    if (!rst_n)
      count <= 16'h0000;
    else if (count == limit)
      count <= 16'h0000;
    else
      count <= count + 1'b1;
  end
endmodule
